 8→export function useEditorTool({ activeTool, dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled, selectedId, selectedType, toolState }) {
 9→  const handler = useMemo(() => {
10→    const ctx = { dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled };
11→
12→    switch (activeTool) {
13→      case TOOLS.WALL:
14→        return createWallDrawHandler(ctx);
15→      case TOOLS.SELECT:
16→        return createSelectHandler(ctx);
17→      case TOOLS.DOOR:
18→        return createDoorPlaceHandler(ctx);
19→      case TOOLS.WINDOW:
20→        return createWindowPlaceHandler(ctx);
21→      default:
22→        return null;
23→    }
24→  }, [activeTool, activeFloorId, viewport.zoom, snapEnabled]);
25→
26→  return {
27→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
28→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
29→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
30→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
31→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
32→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
33→  };
