 83→      const floor = getFloor(activeFloorId);
 84→      const dx = modelPos.x - toolState.startPos.x;
 85→      const dy = modelPos.y - toolState.startPos.y;
 86→
 87→      if (selectedType === 'wall') {
 88→        const wall = floor.walls.find(w => w.id === selectedId);
 89→        if (!wall) return;
 90→
 91→        if (toolState.dragType === 'handle') {
 92→          const handle = toolState.handle;
 93→          dispatch({
 94→            type: 'WALL_UPDATE',
